fn solve(n: i64, m: i64, k: i64) -> i64 {
    if k == 0 {
        return n * m;
    }
    if n == 1 && m == 1 {
        return 1;
    }
    if k >= (n as i64).min(m as i64) / 2 {
        return 1;
    }

    let rows = (n + 2 * k - 1) / (2 * k);
    let cols = (m + 2 * k - 1) / (2 * k);
    rows * cols
}
